head.script:
/* Khởi tạo trang: load dữ liệu sau 50ms và lock các field read-only */
scwin.onpageload = function () {
    window.setTimeout(function () { scwin._loadData(); }, 50);
    window.setTimeout(function () {
        try { inp_assetTags.setReadOnly(true); } catch(e) {}
        try { var el2 = document.getElementById('inp_status'); if (el2) el2.classList.add('dam-select-locked'); } catch(e) {}
    }, 200);
};

/* -1 để lần đầu click bất kỳ folder nào (kể cả root ID=1) đều load được */
scwin._currentFolderId = -1;

/* Trigger khởi động tải dữ liệu ban đầu */
scwin._loadData = function () {
    scwin._loadFolders();
    scwin._loadAssets(1);
};

/* Chuyển flat list API thành rows có DEPTH cho w2:treeview dataType="listed" */
scwin._buildFolderRows = function (folders) {
    var childrenMap = {};
    var allIds = {};
    for (var i = 0; i < folders.length; i++) { allIds[folders[i].folderId] = true; }
    for (var i = 0; i < folders.length; i++) {
        var pid = folders[i].parentFolderId || 0;
        if (!childrenMap[pid]) { childrenMap[pid] = []; }
        childrenMap[pid].push(folders[i]);
    }
    var roots = [];
    for (var i = 0; i < folders.length; i++) {
        var f = folders[i];
        if (!f.parentFolderId || !allIds[f.parentFolderId]) { roots.push(f); }
    }
    var result = [];
    var visit = function (node, depth) {
        result.push({ FOLDER_ID: String(node.folderId), FOLDER_NM: node.folderNm || '', DEPTH: String(depth) });
        var children = childrenMap[node.folderId] || [];
        for (var j = 0; j < children.length; j++) { visit(children[j], depth + 1); }
    };
    for (var i = 0; i < roots.length; i++) { visit(roots[i], 1); }
    return result;
};

/* Gọi GET /api/dam/folders và render cây thư mục vào trvFolder */
scwin._loadFolders = function () {
    fetch('/api/dam/folders')
        .then(function (r) { return r.json(); })
        .then(function (data) {
            if (!data || !data.length) { return; }
            var rows = scwin._buildFolderRows(data);
            try {
                dlFolder.setJSON(rows);
                window.setTimeout(function () {
                    try { trvFolder.expandAll(); } catch (e) {}
                }, 100);
            } catch (e) { console.warn('[Asset] dlFolder.setJSON error', e); }
        })
        .catch(function (e) { console.warn('[Asset] folders error', e); });
};

/* Format kích thước file; dùng com.num.formatByte nếu có, fallback thủ công nếu com chưa load */
scwin._formatFileSize = function (bytes) {
    if (!bytes || Number(bytes) === 0) { return '-'; }
    try {
        if (window.com && com.num && com.num.formatByte) {
            return com.num.formatByte(bytes);
        }
    } catch(e) {}
    var n = Number(bytes);
    if (n >= 1073741824) { return (n / 1073741824).toFixed(1) + ' GB'; }
    if (n >= 1048576)    { return (n / 1048576).toFixed(1) + ' MB'; }
    if (n >= 1024)       { return (n / 1024).toFixed(1) + ' KB'; }
    return n + ' B';
};

/* Gọi GET /api/dam/assets?folderId=X và cập nhật GridView */
scwin._loadAssets = function (folderId) {
    fetch('/api/dam/assets?folderId=' + (folderId || 1))
        .then(function (r) { return r.json(); })
        .then(function (data) {
            var rows = [];
            for (var i = 0; i < data.length; i++) {
                var d = data[i];
                var icon = ((d.fileExt || d.fileType || '')).toUpperCase().replace('.', '');
                rows.push({
                    CHK: '',
                    ASSET_ID: String(d.assetId || ''),
                    ICON: icon,
                    FILE_NM: d.fileNm || '',
                    FILE_TYPE: d.fileType || '',
                    FILE_SIZE: scwin._formatFileSize(d.fileSize),
                    STATUS: d.status || '',
                    TAGS: d.tags || '',
                    CREATOR: d.ownerNm || '',
                    RESOLUTION: d.resolution || '-',
                    UPLOAD_DT: d.uploadDt || '',
                    PREVIEW_URL: d.previewUrl || '/cm/dam/images/preview/document.svg'
                });
            }
            /* Lưu full dataset, reset sort/filter về mặc định khi đổi folder */
            scwin._allAssets     = rows;
            scwin._sortCycleIdx  = 0;
            scwin._filterState   = { types: {}, statuses: {} };
            var oldPanel = document.getElementById('dam_filter_panel');
            if (oldPanel && oldPanel.parentNode) { oldPanel.parentNode.removeChild(oldPanel); }

            try { dlAsset.setJSON(rows); } catch (e) { console.warn('[Asset] setJSON failed', e); }
            scwin._clearDetail();
            scwin._updateSortBtn();
            scwin._updateFilterBtn();
            if (rows.length > 0) {
                window.setTimeout(function () { scwin._styleIconBadges(); }, 100);
                window.setTimeout(function () { scwin._styleIconBadges(); }, 500);
            }
            window.setTimeout(function () { scwin._attachSortOnMousedown(); }, 150);
        })
        .catch(function (e) { console.warn('[Asset] assets error', e); });
};

/* Xử lý click node TreeView; bỏ qua nếu folder không thay đổi */
scwin.trvFolder_onclick = function (treeObj) {
    var nodeValue = trvFolder.getSelectedValue();
    if (!nodeValue) { return; }
    var fid = parseInt(nodeValue, 10);
    if (isNaN(fid) || fid <= 0) { return; }
    if (fid === scwin._currentFolderId) { return; }
    scwin._currentFolderId = fid;
    scwin._loadAssets(fid);
};

/* Xử lý click row GridView; delay 30ms để WebSquare cập nhật focused row index */
scwin.grdAsset_onclick = function () {
    window.setTimeout(function () {
        try {
            var idx = grdAsset.getFocusedRowIndex();
            if (idx >= 0) { scwin._applyDetail(idx); }
        } catch (e) {}
    }, 30);
};

/* Màu sắc bottom-band theo extension — căn theo mẫu thiết kế */
scwin._FILE_ICON_COLORS = {
    "PDF":  "#f44336", "DOC":  "#1e88e5", "DOCX": "#1e88e5",
    "XLS":  "#43a047", "XLSX": "#43a047", "PPT":  "#ff7043", "PPTX": "#ff7043",
    "JPG":  "#43a047", "JPEG": "#43a047", "PNG":  "#1e88e5",
    "GIF":  "#8e24aa", "SVG":  "#00897b", "PSD":  "#5e35b1",
    "MP4":  "#fb8c00", "MOV":  "#f4511e", "AVI":  "#f4511e",
    "MP3":  "#3949ab", "WAV":  "#3949ab", "AAC":  "#3949ab",
    "ZIP":  "#546e7a", "RAR":  "#546e7a", "7Z":   "#546e7a"
};

/* Tạo data URL SVG hình tài liệu (thân trắng, góc gấp, band màu dưới + chữ extension) */
scwin._makeFileIcon = function (ext) {
    var color = scwin._FILE_ICON_COLORS[ext] || '#546e7a';
    var lbl   = ext.substring(0, 4);
    var svg = '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 32 40">'
        + '<path d="M2,0 L22,0 L32,10 L32,40 L2,40 Z" fill="#ffffff" stroke="#d1d5db" stroke-width="1.5"/>'
        + '<path d="M22,0 L22,10 L32,10 Z" fill="#e5e7eb"/>'
        + '<rect x="2" y="26" width="30" height="14" fill="' + color + '"/>'
        + '<text x="16" y="37" font-family="Arial,sans-serif" font-size="8" font-weight="bold" fill="#ffffff" text-anchor="middle">' + lbl + '</text>'
        + '</svg>';
    return 'data:image/svg+xml;charset=utf-8,' + encodeURIComponent(svg);
};

/* Inject <img> SVG icon vào ô ICON; đọc extension từ label text của DataList.
   Nếu cell đã có img nhưng alt không khớp ext (do WebSquare tái dùng DOM row),
   xoá img cũ và tạo lại — tránh MP4 row hiển thị icon JPG từ lần load trước. */
scwin._styleIconBadges = function () {
    try {
        var cells = document.querySelectorAll(".dam-asset-grid-view .dam-cell-icon");
        for (var i = 0; i < cells.length; i++) {
            var cell = cells[i];
            var labelEl = cell.querySelector(".w2grid_label");
            var ext = (labelEl ? (labelEl.textContent || labelEl.innerText || '') : (cell.textContent || '')).trim().toUpperCase().replace('.', '');
            if (!ext) { ext = 'FILE'; }
            /* ẩn label text bằng inline style */
            if (labelEl) { labelEl.style.cssText = 'display:none!important;visibility:hidden!important;'; }
            /* giữ lại img nếu đã đúng ext; xoá nếu sai (DOM row bị tái dùng) */
            var existingImg = cell.querySelector(".dam-icon-img");
            if (existingImg) {
                if (existingImg.alt === ext) { continue; }
                existingImg.parentNode.removeChild(existingImg);
            }
            var img = document.createElement('img');
            img.className  = 'dam-icon-img';
            img.src        = scwin._makeFileIcon(ext);
            img.alt        = ext;
            img.style.cssText = 'width:28px;height:34px;object-fit:contain;display:block;margin:0 auto;pointer-events:none;';
            cell.appendChild(img);
        }
    } catch (e) { /* ignore */ }
};

/* Re-apply badge sau mỗi lần GridView vẽ lại row */
scwin.grdAsset_ondrawendrow = function () {
    scwin._styleIconBadges();
};

/* Re-apply badge sau khi sort (double timeout: 50ms cho DOM render, 300ms cho WebSquare) */
scwin.grdAsset_onsort = function () {
    window.setTimeout(function () { scwin._styleIconBadges(); }, 50);
    window.setTimeout(function () { scwin._styleIconBadges(); }, 300);
};

/* Trạng thái sort hiện tại: { colId: 'asc' | 'desc' } */
scwin._sortState = {};

/* ─── Sort button ──────────────────────────────────────────────────── */

/* Toàn bộ dataset chưa lọc — nguồn gốc để _applyFiltersAndSort làm việc */
scwin._allAssets = [];

/* Danh sách preset sort; null = không sort (thứ tự load gốc) */
scwin._sortCycle = [
    null,
    { col: 'FILE_NM',   dir: 'asc',  lbl: 'Name ↑' },
    { col: 'FILE_NM',   dir: 'desc', lbl: 'Name ↓' },
    { col: 'FILE_TYPE', dir: 'asc',  lbl: 'Type ↑' },
    { col: 'FILE_TYPE', dir: 'desc', lbl: 'Type ↓' },
    { col: 'FILE_SIZE', dir: 'asc',  lbl: 'Size ↑' },
    { col: 'FILE_SIZE', dir: 'desc', lbl: 'Size ↓' },
    { col: 'STATUS',    dir: 'asc',  lbl: 'Status ↑' },
    { col: 'UPLOAD_DT', dir: 'desc', lbl: 'Date ↓' }
];
scwin._sortCycleIdx = 0;

/* ─── Filter state ─────────────────────────────────────────────────── */
scwin._filterState = { types: {}, statuses: {} };

/* Áp filter + sort lên _allAssets rồi đẩy vào dlAsset */
scwin._applyFiltersAndSort = function () {
    var actTypes = Object.keys(scwin._filterState.types).filter(function (k) { return scwin._filterState.types[k]; });
    var actSts   = Object.keys(scwin._filterState.statuses).filter(function (k) { return scwin._filterState.statuses[k]; });

    var rows = scwin._allAssets.filter(function (r) {
        if (actTypes.length && actTypes.indexOf(r.FILE_TYPE) === -1) { return false; }
        if (actSts.length   && actSts.indexOf(r.STATUS)    === -1) { return false; }
        return true;
    });

    var preset = scwin._sortCycle[scwin._sortCycleIdx];
    if (preset) {
        rows = rows.slice().sort(function (a, b) {
            var va = String(a[preset.col] || ''), vb = String(b[preset.col] || '');
            var cmp = va.localeCompare(vb, undefined, { numeric: true });
            return preset.dir === 'asc' ? cmp : -cmp;
        });
    }

    try { dlAsset.setJSON(rows); } catch (e) {}
    scwin._clearDetail();
    if (rows.length > 0) {
        window.setTimeout(scwin._styleIconBadges, 100);
        window.setTimeout(scwin._styleIconBadges, 450);
    }
    scwin._updateSortBtn();
    scwin._updateFilterBtn();
};

/* Cập nhật label nút sort theo preset hiện tại */
scwin._updateSortBtn = function () {
    var preset = scwin._sortCycle[scwin._sortCycleIdx];
    var lbl = preset ? preset.lbl : '↑↓';
    try { btn_filesSort.setLabel(lbl); } catch (e) {}
    try {
        var el = document.getElementById('btn_filesSort');
        if (el) {
            var w = el.querySelector('.w2trigger_label, button, span');
            if (w) { w.textContent = lbl; }
            el.title = preset ? ('Sort: ' + lbl) : 'Sort';
            el.style.color    = preset ? '#1d4ed8' : '';
            el.style.fontWeight = preset ? '700' : '';
        }
    } catch (e) {}
};

/* Tô màu nút filter khi có filter đang bật */
scwin._updateFilterBtn = function () {
    var actTypes = Object.keys(scwin._filterState.types).filter(function (k) { return scwin._filterState.types[k]; });
    var actSts   = Object.keys(scwin._filterState.statuses).filter(function (k) { return scwin._filterState.statuses[k]; });
    var active   = actTypes.length > 0 || actSts.length > 0;
    try {
        var el = document.getElementById('btn_filesFilter');
        if (el) {
            el.style.background   = active ? '#dbeafe' : '';
            el.style.color        = active ? '#1d4ed8' : '';
            el.style.borderColor  = active ? '#93c5fd' : '';
            el.style.fontWeight   = active ? '700' : '';
        }
    } catch (e) {}
};

/* Sort button — cycle preset mỗi lần bấm */
scwin.btn_filesSort_onclick = function () {
    scwin._sortCycleIdx = (scwin._sortCycleIdx + 1) % scwin._sortCycle.length;
    scwin._applyFiltersAndSort();
};

/* Filter button — toggle inline filter panel */
scwin.btn_filesFilter_onclick = function () {
    var panel = document.getElementById('dam_filter_panel');
    if (!panel) { scwin._buildFilterPanel(); return; }
    panel.style.display = panel.style.display === 'none' ? '' : 'none';
};

/* Xây filter panel động dựa trên giá trị thực tế trong _allAssets */
scwin._buildFilterPanel = function () {
    var body = document.querySelector('.dam-asset-files-body');
    if (!body) { return; }

    var types = {}, statuses = {};
    for (var i = 0; i < scwin._allAssets.length; i++) {
        var r = scwin._allAssets[i];
        if (r.FILE_TYPE) { types[r.FILE_TYPE]   = true; }
        if (r.STATUS)    { statuses[r.STATUS] = true; }
    }

    var html = '<div class="dam-filter-inner">';

    html += '<div class="dam-filter-col"><span class="dam-filter-col-title">File Type</span>';
    Object.keys(types).sort().forEach(function (t) {
        var chk = scwin._filterState.types[t] ? ' checked' : '';
        html += '<label class="dam-filter-item"><input type="checkbox" data-dim="types" data-val="' + t + '"' + chk + '> ' + t + '</label>';
    });
    html += '</div>';

    html += '<div class="dam-filter-col"><span class="dam-filter-col-title">Status</span>';
    Object.keys(statuses).sort().forEach(function (s) {
        var chk = scwin._filterState.statuses[s] ? ' checked' : '';
        html += '<label class="dam-filter-item"><input type="checkbox" data-dim="statuses" data-val="' + s + '"' + chk + '> ' + s + '</label>';
    });
    html += '</div>';

    html += '<button class="dam-filter-clear-btn" id="dam_filter_clear_btn">Clear all</button>';
    html += '</div>';

    var panel = document.createElement('div');
    panel.id = 'dam_filter_panel';
    panel.className = 'dam-filter-panel';
    panel.innerHTML = html;
    body.insertBefore(panel, body.firstChild);

    panel.querySelectorAll('input[type="checkbox"]').forEach(function (cb) {
        cb.addEventListener('change', function () {
            scwin._filterState[cb.getAttribute('data-dim')][cb.getAttribute('data-val')] = cb.checked;
            scwin._applyFiltersAndSort();
        });
    });

    var clearBtn = document.getElementById('dam_filter_clear_btn');
    if (clearBtn) {
        clearBtn.addEventListener('click', function () {
            scwin._filterState = { types: {}, statuses: {} };
            panel.querySelectorAll('input[type="checkbox"]').forEach(function (cb) { cb.checked = false; });
            scwin._applyFiltersAndSort();
        });
    }
};

/* mousedown capture — fires before focus-transfer, so works on first click */
scwin._attachSortOnMousedown = function () {
    if (document._damSortAttached) { return; }
    document._damSortAttached = true;

    /* inject initial ⇅ into sortable header cells */
    var sortableIdxMap = { 2: true, 3: true, 4: true, 5: true };
    var tryInitIcons = function () {
        var sels = [
            ".dam-asset-grid-view .w2grid_header .w2grid_cell",
            ".dam-asset-grid-view .w2grid_header td",
            ".dam-asset-grid-view .w2grid_header th",
            ".dam-asset-grid-view thead td",
            ".dam-asset-grid-view thead th"
        ];
        var hcells = null;
        for (var s = 0; s < sels.length; s++) {
            var found = document.querySelectorAll(sels[s]);
            if (found && found.length > 0) { hcells = found; break; }
        }
        if (!hcells || !hcells.length) { return; }
        for (var i = 0; i < hcells.length; i++) {
            if (!sortableIdxMap[i]) { continue; }
            if (!hcells[i].querySelector(".dam-sort-indicator")) {
                var sp = document.createElement("span");
                sp.className = "dam-sort-indicator";
                sp.textContent = " ⇅";
                sp.style.cssText = "font-size:0.7rem;color:#94a3b8;pointer-events:none;";
                hcells[i].appendChild(sp);
            }
        }
    };
    tryInitIcons();
    window.setTimeout(tryInitIcons, 300);

    document.addEventListener("mousedown", function (e) {
        var target = e.target;
        if (!target || !target.closest) { return; }
        if (!target.closest(".dam-asset-grid-view")) { return; }
        var headerCell =
            target.closest(".w2grid_header .w2grid_cell") ||
            target.closest(".w2grid_header td") ||
            target.closest(".w2grid_header th") ||
            target.closest("thead td") ||
            target.closest("thead th");
        if (!headerCell) { return; }
        var siblings = headerCell.parentElement ? headerCell.parentElement.children : [];
        var idx = -1;
        for (var i = 0; i < siblings.length; i++) {
            if (siblings[i] === headerCell) { idx = i; break; }
        }
        var sortableMap = { 2: "FILE_NM", 3: "FILE_TYPE", 4: "FILE_SIZE", 5: "STATUS" };
        var colId = sortableMap[idx];
        if (!colId) { return; }
        var cur = scwin._sortState[colId] || "none";
        var next = cur === "asc" ? "desc" : "asc";
        scwin._sortState = {};
        scwin._sortState[colId] = next;
        /* build rows array from DataList row-by-row (getJSON may not return array) */
        try {
            var count = dlAsset.getRowCount ? dlAsset.getRowCount() : 0;
            var rows = [];
            for (var r = 0; r < count; r++) { rows.push(dlAsset.getRowJSON(r)); }
            if (rows.length) {
                rows.sort(function (a, b) {
                    var va = String(a[colId] || "");
                    var vb = String(b[colId] || "");
                    return next === "asc"
                        ? va.localeCompare(vb, undefined, { numeric: true })
                        : vb.localeCompare(va, undefined, { numeric: true });
                });
                dlAsset.setJSON(rows);
                scwin._applyDetail(0);
                window.setTimeout(function () { scwin._styleIconBadges(); }, 50);
            }
        } catch (ex) { console.warn("[Asset] sort error", ex); }
        /* update header indicators */
        var old = document.querySelectorAll(".dam-asset-grid-view .dam-sort-indicator");
        for (var j = 0; j < old.length; j++) { old[j].textContent = " ⇅"; old[j].style.color = "#94a3b8"; }
        var activeInd = headerCell.querySelector(".dam-sort-indicator");
        if (activeInd) {
            activeInd.textContent = next === "asc" ? " ▲" : " ▼";
            activeInd.style.color = "#334155";
        }
    }, true);

    /* Chặn dblclick trên ô icon — ngăn GridView vào edit mode và lộ URL thô */
    document.addEventListener('dblclick', function (e) {
        if (!e.target || !e.target.closest) { return; }
        if (!e.target.closest('.dam-cell-icon')) { return; }
        e.stopImmediatePropagation();
        e.preventDefault();
        window.setTimeout(scwin._styleIconBadges, 30);
    }, true);
};

/* Xóa nội dung panel detail và reset trạng thái khi không có row nào được chọn */
scwin._clearDetail = function () {
    scwin._lastDetailRow = -1;
    scwin._editMode = false;
    try {
        var pEl = document.querySelector('.dam-asset-preview');
        if (pEl) { pEl.style.backgroundImage = ''; }
    } catch (e) {}
    try { inp_fileName.setValue(''); }   catch (e) {}
    try { inp_assetTags.setValue(''); } catch (e) {}
    try { inp_status.setValue(''); }    catch (e) {}
    try { inp_creator.setValue(''); }    catch (e) {}
    try { inp_resolution.setValue(''); } catch (e) {}
    try { inp_uploaded.setValue(''); }   catch (e) {}
    scwin._setEditFields(false);
};

/* Index row đang hiển thị trong panel detail (-1 = chưa chọn) */
scwin._lastDetailRow = -1;

/* Điền thông tin asset đã chọn vào panel detail; bỏ qua nếu row không thay đổi */
scwin._applyDetail = function (rowIndex) {
    if (rowIndex === scwin._lastDetailRow) { return; }
    if (scwin._editMode) { scwin._editMode = false; }
    scwin._lastDetailRow = rowIndex;
    var row = dlAsset.getRowJSON(rowIndex);
    if (!row) { return; }

    try {
        var url = row.PREVIEW_URL || "/cm/dam/images/preview/document.svg";
        var pEl = document.querySelector(".dam-asset-preview");
        if (pEl) { pEl.style.backgroundImage = "url('" + url + "')"; }
    } catch (e) {}

    /* direct component access (with(scopeObj) scope) */
    try { inp_fileName.setValue(row.FILE_NM || ""); }          catch(e) {}
    try { inp_assetTags.setValue(row.TAGS || ''); } catch(e) {}
    try { inp_creator.setValue(row.CREATOR || ""); }        catch(e) {}
    try { inp_resolution.setValue(row.RESOLUTION || "-"); } catch(e) {}
    try { inp_uploaded.setValue(row.UPLOAD_DT || ""); }     catch(e) {}
    try { inp_status.setValue(row.STATUS || ""); }          catch(e) {}

    /* re-lock selects after setValue — WebSquare may re-render and strip classes */
    scwin._setEditFields(false);
};

/* Tạo file .txt chứa thông tin asset và kích hoạt tải xuống qua Blob URL */
scwin.btn_download_onclick = function () {
    var idx = scwin._lastDetailRow;
    if (idx < 0) { return; }
    var row = dlAsset.getRowJSON(idx);
    if (!row) { return; }
    var lines = [
        'Digital Asset Manager - File Info',
        '==================================',
        'File Name   : ' + (row.FILE_NM    || '-'),
        'File Type   : ' + (row.FILE_TYPE  || '-'),
        'File Size   : ' + (row.FILE_SIZE  || '-'),
        'Status      : ' + (row.STATUS     || '-'),
        'Tags        : ' + (row.TAGS       || '-'),
        'Creator     : ' + (row.CREATOR    || '-'),
        'Resolution  : ' + (row.RESOLUTION || '-'),
        'Upload Date : ' + (row.UPLOAD_DT  || '-'),
        '',
        'Generated   : ' + new Date().toLocaleString()
    ];
    var blob = new Blob([lines.join('\n')], { type: 'text/plain;charset=utf-8' });
    var url  = URL.createObjectURL(blob);
    var a    = document.createElement('a');
    a.href     = url;
    a.download = (row.FILE_NM || 'asset').replace(/[\\/:*?"<>|]/g, '_') + '_info.txt';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
};

/* Flag trạng thái edit: true = đang chỉnh sửa, false = chỉ xem */
scwin._editMode = false;

/* ─── Validation ───────────────────────────────────────────────────── */

/* Danh sách status hợp lệ — khớp với xf:choices trong XML */
scwin._VALID_STATUSES = ['Draft', 'Published', 'Archived', 'Review', 'Inactive'];

/* File Name: required, tối đa 200 ký tự, không chứa ký tự path nguy hiểm */
scwin._validateFileName = function (name) {
    if (!name || name.trim() === '')     { return { ok: false, msg: 'File Name không được để trống.' }; }
    if (name.trim().length > 200)        { return { ok: false, msg: 'File Name tối đa 200 ký tự.' }; }
    if (/[\/\\:*?"<>|]/.test(name))      { return { ok: false, msg: 'File Name không được chứa: / \\ : * ? " < > |' }; }
    return { ok: true };
};

/* Status: bắt buộc chọn, phải thuộc danh sách hợp lệ */
scwin._validateStatus = function (status) {
    if (!status || status.trim() === '')                  { return { ok: false, msg: 'Vui lòng chọn Status.' }; }
    if (scwin._VALID_STATUSES.indexOf(status) === -1)    { return { ok: false, msg: 'Status không hợp lệ.' }; }
    return { ok: true };
};

/* Tags: tùy chọn, tối đa 10 tag, mỗi tag ≤ 50 ký tự */
scwin._validateTags = function (tagStr) {
    if (!tagStr || tagStr.trim() === '') { return { ok: true }; }
    var tags = tagStr.split(',').map(function (t) { return t.trim(); }).filter(function (t) { return t !== ''; });
    if (tags.length > 10)               { return { ok: false, msg: 'Tối đa 10 tags.' }; }
    for (var i = 0; i < tags.length; i++) {
        if (tags[i].length > 50)        { return { ok: false, msg: 'Mỗi tag tối đa 50 ký tự.' }; }
    }
    return { ok: true };
};

/* Hiển thị lỗi inline dưới field; tái dùng span nếu đã tồn tại */
scwin._showFieldError = function (fieldId, msg) {
    var errorId = 'err_' + fieldId;
    var existing = document.getElementById(errorId);
    if (existing) { existing.textContent = msg; existing.style.display = 'block'; return; }
    var field = document.getElementById(fieldId);
    if (!field) { return; }
    var row = field.closest ? field.closest('.dam-form-row') : field.parentNode;
    var span = document.createElement('span');
    span.id = errorId;
    span.className = 'dam-field-error';
    span.textContent = msg;
    row.appendChild(span);
};

/* Xóa tất cả error messages đang hiển thị */
scwin._clearFieldErrors = function () {
    var errors = document.querySelectorAll('.dam-field-error');
    for (var i = 0; i < errors.length; i++) { errors[i].style.display = 'none'; errors[i].textContent = ''; }
};

/* Xóa error của riêng một field */
scwin._clearFieldError = function (fieldId) {
    var el = document.getElementById('err_' + fieldId);
    if (el) { el.style.display = 'none'; el.textContent = ''; }
};

/* Gắn real-time validation: File Name blur + Status change + Tags qua popup */
scwin._attachLiveValidation = function () {
    /* File Name — xóa error khi user bắt đầu nhập, kiểm tra khi rời field */
    try {
        var fnWrap  = document.getElementById('inp_fileName');
        var fnInput = fnWrap ? fnWrap.querySelector('input, textarea') : null;
        if (fnInput && !fnInput._damLive) {
            fnInput._damLive = true;
            fnInput.addEventListener('input', function () { scwin._clearFieldError('inp_fileName'); });
            fnInput.addEventListener('blur',  function () {
                var v = scwin._validateFileName(fnInput.value);
                if (!v.ok) { scwin._showFieldError('inp_fileName', v.msg); }
            });
        }
    } catch(e) {}

    /* Status — kiểm tra ngay khi chọn */
    try {
        var selEl = document.getElementById('inp_status');
        if (selEl && !selEl._damLive) {
            selEl._damLive = true;
            selEl.addEventListener('change', function () {
                var v = scwin._validateStatus(selEl.value);
                if (!v.ok) { scwin._showFieldError('inp_status', v.msg); }
                else        { scwin._clearFieldError('inp_status'); }
            });
        }
    } catch(e) {}
};

/* Lock/unlock các field theo chế độ; cập nhật label nút Edit/Save */
scwin._setEditFields = function (editable) {
    /* inp_fileName: w2:input works fine with setReadOnly */
    try { inp_fileName.setReadOnly(!editable); } catch(e) {}
    try {
        var fnWrap = document.getElementById('inp_fileName');
        if (fnWrap) {
            var fnInps = fnWrap.querySelectorAll('input,textarea');
            for (var k = 0; k < fnInps.length; k++) {
                fnInps[k].style.outline    = editable ? '2px solid #6366f1' : '';
                fnInps[k].style.background = editable ? '#fff' : '';
            }
        }
    } catch(e) {}
    /* inp_assetTags, inp_status: renderType="select" — ID is on the <select> itself, style el directly */
    try {
        var tagsBtn = document.querySelector('.dam-tags-edit-btn');
        if (tagsBtn) tagsBtn.style.display = editable ? '' : 'none';
    } catch(e) {}
    try {
        var el = document.getElementById('inp_status');
        if (el) {
            if (editable) {
                el.classList.remove('dam-select-locked');
                el.style.outline = '2px solid #6366f1';
                el.style.background = '#fff';
            } else {
                el.classList.add('dam-select-locked');
                el.style.outline = '';
                el.style.background = '';
            }
        }
    } catch(e) {}
    try { btn_edit.setLabel(editable ? 'Save Changes' : 'Edit Metadata'); } catch(e) {}
    try {
        var btnEl = document.getElementById('btn_edit');
        if (btnEl) {
            var walker = document.createTreeWalker(btnEl, 4, null, false);
            var tNode = walker.nextNode();
            if (tNode) { tNode.nodeValue = editable ? 'Save Changes' : 'Edit Metadata'; }
        }
    } catch(e) {}
    /* Gắn live validation sau khi DOM đã được WebSquare cập nhật */
    if (editable) { window.setTimeout(scwin._attachLiveValidation, 60); }
};

/* ─── Version helpers (dùng chung logic với file_browser.xml) ───────── */

/* Phân tích verNo thành số nguyên để so sánh (v2.3 → 2000003) */
scwin._parseVerNo = function (verNo) {
    var m = String(verNo || '').trim().match(/^(?:v|V)?(\d+)(?:\.(\d+))?$/);
    if (m) { return parseInt(m[1], 10) * 1000000 + parseInt(m[2] || '0', 10); }
    return -1;
};

/* Tính version number tiếp theo (v1.2 → v1.3, v1.9 → v1.10) */
scwin._nextVersionNo = function (currentVerNo) {
    var m = String(currentVerNo || '').trim().match(/^(?:v|V)?(\d+)(?:\.(\d+))?$/);
    var major = 1, minor = 0;
    if (m) { major = parseInt(m[1], 10) || 1; minor = parseInt(m[2] || '0', 10) || 0; }
    return 'v' + major + '.' + (minor + 1);
};

/* Chọn version mới nhất từ danh sách (ưu tiên verNo, tie-break bằng verId) */
scwin._pickLatestVersion = function (versions) {
    var list = versions || [];
    if (!list.length) { return null; }
    var latest = list[0];
    for (var i = 1; i < list.length; i++) {
        var cur = list[i];
        var cNo = scwin._parseVerNo(cur.verNo), lNo = scwin._parseVerNo(latest.verNo);
        if (cNo > lNo) { latest = cur; continue; }
        if (cNo === lNo && parseInt(cur.verId, 10) > parseInt(latest.verId, 10)) { latest = cur; }
    }
    return latest;
};

/* Tự động sinh change log dựa trên field nào thay đổi so với giá trị gốc */
scwin._generateChangeLog = function (original, fileNm, tags, status) {
    var changed = [];
    if ((original.FILE_NM || '') !== (fileNm  || '')) { changed.push('File Name'); }
    if ((original.TAGS    || '') !== (tags    || '')) { changed.push('Tags'); }
    if ((original.STATUS  || '') !== (status  || '')) { changed.push('Status'); }
    var d = new Date(), pad = function (n) { return n < 10 ? '0' + n : '' + n; };
    var ts = d.getFullYear() + '-' + pad(d.getMonth() + 1) + '-' + pad(d.getDate())
           + ' ' + pad(d.getHours()) + ':' + pad(d.getMinutes());
    return (changed.length ? 'Updated ' + changed.join(', ') : 'Metadata reviewed') + ' — ' + ts;
};

/* Hiện toast nhỏ ở góc phải dưới sau khi save + tạo version thành công */
scwin._showSaveToast = function (msg) {
    var old = document.getElementById('dam_save_toast');
    if (old && old.parentNode) { old.parentNode.removeChild(old); }
    var t = document.createElement('div');
    t.id = 'dam_save_toast';
    t.style.cssText = 'position:fixed;bottom:1.5rem;right:1.5rem;background:#1f2733;color:#fff;'
        + 'padding:0.75rem 1.25rem;border-radius:0.5rem;font-size:0.82rem;z-index:9999;'
        + 'box-shadow:0 4px 12px rgba(0,0,0,.25);max-width:340px;line-height:1.5;';
    t.innerHTML = '<strong style="color:#4ade80;">✓ Saved & versioned</strong>'
        + '<br><span style="color:#94a3b8;font-size:0.78rem;">' + msg + '</span>';
    document.body.appendChild(t);
    window.setTimeout(function () { if (t.parentNode) { t.parentNode.removeChild(t); } }, 4500);
};

/* Cập nhật DataList tại chỗ, PUT metadata, rồi tự động POST version mới với change log tự sinh */
scwin._saveMetadata = function (idx) {
    try {
        var count = dlAsset.getRowCount ? dlAsset.getRowCount() : 0;
        var rows = [];
        for (var r = 0; r < count; r++) { rows.push(dlAsset.getRowJSON(r)); }

        /* Lưu giá trị gốc trước khi overwrite — dùng để sinh change log */
        var original = { FILE_NM: rows[idx].FILE_NM, TAGS: rows[idx].TAGS, STATUS: rows[idx].STATUS };
        var fileNm = inp_fileName.getValue();
        var tags   = inp_assetTags.getValue() || '';
        var status = inp_status.getValue();
        rows[idx].FILE_NM = fileNm;
        rows[idx].TAGS    = tags;
        rows[idx].STATUS  = status;
        dlAsset.setJSON(rows);

        var assetId = rows[idx].ASSET_ID;
        if (!assetId) { return; }

        var changeLog = scwin._generateChangeLog(original, fileNm, tags, status);
        var creator   = rows[idx].CREATOR || '';
        var fileType  = rows[idx].FILE_TYPE || null;

        /* Bước 1 — PUT cập nhật metadata asset */
        fetch('/api/dam/assets/' + assetId, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ fileNm: fileNm, tags: tags, status: status, fileType: fileType })
        })
        .then(function (r) { return r.json(); })
        /* Bước 2 — GET version list để tính nextVerNo */
        .then(function () { return fetch('/api/dam/assets/' + assetId); })
        .then(function (r) { return r.json(); })
        .then(function (res) {
            var latest  = scwin._pickLatestVersion((res && res.versions) || []);
            var nextVer = scwin._nextVersionNo(latest ? latest.verNo : 'v1.0');
            /* Bước 3 — POST tạo version mới với change log tự sinh */
            return fetch('/api/dam/assets/' + assetId + '/versions', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ verNo: nextVer, changeLog: changeLog, ownerNm: creator, fileUrl: fileNm })
            });
        })
        .then(function (r) { return r.json(); })
        .then(function () { scwin._showSaveToast(changeLog); })
        .catch(function (e) { console.warn('[Asset] saveMetadata error', e); });
    } catch(e) { console.warn('[Asset] saveMetadata error', e); }
};

/* Toggle chế độ view/edit; validate các field rồi confirm trước khi lưu */
scwin.btn_edit_onclick = function () {
    if (scwin._lastDetailRow < 0) { return; }
    if (!scwin._editMode) {
        scwin._editMode = true;
        scwin._clearFieldErrors();
        scwin._setEditFields(true);
        return;
    }
    /* Thu thập giá trị hiện tại */
    var fileNm = ''; try { fileNm = inp_fileName.getValue();      } catch(e) {}
    var status = ''; try { status = inp_status.getValue();        } catch(e) {}
    var tags   = ''; try { tags   = inp_assetTags.getValue() || '';} catch(e) {}

    /* Chạy validation từng field */
    scwin._clearFieldErrors();
    var vfn = scwin._validateFileName(fileNm);
    var vst = scwin._validateStatus(status);
    var vtg = scwin._validateTags(tags);

    var hasError = false;
    if (!vfn.ok) { scwin._showFieldError('inp_fileName',  vfn.msg); hasError = true; }
    if (!vst.ok) { scwin._showFieldError('inp_status',    vst.msg); hasError = true; }
    if (!vtg.ok) { scwin._showFieldError('inp_assetTags', vtg.msg); hasError = true; }
    if (hasError) { return; }

    if (!window.confirm('Bạn có chắc muốn lưu thay đổi?')) { return; }
    var idx = scwin._lastDetailRow;
    scwin._saveMetadata(idx);
    scwin._editMode = false;
    scwin._lastDetailRow = -1;
    scwin._setEditFields(false);
    scwin._applyDetail(idx);
};

/* Danh sách 21 tag có thể chọn cho asset */
scwin._ALL_TAGS = [
    {v:'Marketing',l:'Marketing'}, {v:'Campaign',l:'Campaign'}, {v:'Branding',l:'Branding'},
    {v:'Internal',l:'Internal'},   {v:'External',l:'External'}, {v:'Confidential',l:'Confidential'},
    {v:'Digital',l:'Digital'},     {v:'Print',l:'Print'},       {v:'Web',l:'Web'},
    {v:'SocialMedia',l:'Social Media'}, {v:'Photo',l:'Photo'}, {v:'Video',l:'Video'},
    {v:'Legacy',l:'Legacy'},       {v:'HR',l:'HR'},             {v:'Training',l:'Training'},
    {v:'Finance',l:'Finance'},     {v:'Legal',l:'Legal'},       {v:'Product',l:'Product'},
    {v:'Background',l:'Background'},{v:'Brand',l:'Brand'},      {v:'Q4',l:'Q4'}
];

/* Mở popup chọn tag, đánh dấu sẵn các tag hiện tại */
scwin.btn_editTags_onclick = function () {
    var current = {};
    try {
        (inp_assetTags.getValue() || '').split(',').forEach(function(t) {
            var s = t.trim(); if (s) current[s] = true;
        });
    } catch(e) {}

    var body = document.querySelector('.dam-tag-popup-body');
    if (!body) { return; }
    body.innerHTML = '';
    scwin._ALL_TAGS.forEach(function(tag) {
        var lbl = document.createElement('label');
        lbl.className = 'dam-tag-popup-item';
        var cb = document.createElement('input');
        cb.type = 'checkbox'; cb.value = tag.v;
        if (current[tag.v]) { cb.checked = true; }
        lbl.appendChild(cb);
        lbl.appendChild(document.createTextNode(' ' + tag.l));
        body.appendChild(lbl);
    });

    var popup = document.querySelector('.dam-tag-popup');
    if (popup) { popup.style.display = ''; }
};

/* Thu thập checkbox đã chọn; validate trước khi đóng popup */
scwin.btn_confirmTags_onclick = function () {
    var checked = document.querySelectorAll('.dam-tag-popup-body input[type="checkbox"]:checked');
    var vals = [];
    for (var i = 0; i < checked.length; i++) { vals.push(checked[i].value); }
    var tagStr = vals.join(',');
    var v = scwin._validateTags(tagStr);
    if (!v.ok) {
        /* Hiện lỗi bên trong popup thay vì đóng */
        var errEl = document.getElementById('dam_tag_popup_err');
        if (!errEl) {
            errEl = document.createElement('p');
            errEl.id = 'dam_tag_popup_err';
            errEl.style.cssText = 'color:#ef4444;font-size:0.75rem;margin:0 0 0.5rem;font-weight:500;';
            var foot = document.querySelector('.dam-tag-popup-foot');
            if (foot) { foot.parentNode.insertBefore(errEl, foot); }
        }
        errEl.textContent = v.msg;
        return;
    }
    /* Xóa lỗi cũ nếu có, đóng popup, cập nhật field */
    var errOld = document.getElementById('dam_tag_popup_err');
    if (errOld) { errOld.textContent = ''; }
    try { inp_assetTags.setValue(tagStr); } catch(e) {}
    scwin._clearFieldError('inp_assetTags');
    var popup = document.querySelector('.dam-tag-popup');
    if (popup) { popup.style.display = 'none'; }
};

/* Đóng popup tag mà không lưu thay đổi */
scwin.btn_cancelTags_onclick = function () {
    var popup = document.querySelector('.dam-tag-popup');
    if (popup) { popup.style.display = 'none'; }
};
